class ShoppingCart:
    def __init__(self):
        self.items = []
        self.user = None
        self.discount_codes = {
            'ADMIN10': self.is_admin,
            'PREMIUM20': self.is_premium,
            'STANDARD5' : lambda: True
        }

    def add_item(self, item):
        self.items.append(item)

    def is_admin(self):
        return self.user.is_admin

    def is_premium(self):
        return self.user.tier == 'premium'

    def apply_discount(self, code):
        if code not in self.discount_codes or not self.discount_codes[code](self):
            return None
        discount = {
            'ADMIN10': 0.1,
            'PREMIUM20': 0.2,
            'STANDARD5': 0.05
        }[code]
        return self._calculate_with_discount(discount)

    def _calculate_with_discount(self, discount):
        total = sum([item.price for item in self.items]) * (1 - discount)
        return total

    def calculate_tax(self):
        return self._calculate_with_discount(0.07)  # Tax rate example: 7%

    def process_payment(self):
        # Simulate payment processing
        if self.calculate_total() < 10:
            raise ValueError("Minimum purchase amount is $10.")
        return True

    def create_order(self):
        # Create order record in database
        pass

    def calculate_total(self):
        total = self.calculate_tax()
        if discount := self._applied_discount:
            total -= discount
        return total

    @property
    def _applied_discount(self):
        for code in self.discount_codes:
            if self.discount_codes[code](self):
                return self.apply_discount(code)
        return None

class Item:
    def __init__(self, name, price):
        self.name = name
